// Pair each fetch result with its watchlist row (same order, same count)
const rows = $('Read watchlist').all();
const results = $input.all();

// FNV-1a content hash — no external modules needed
function contentHash(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = Math.imul(h, 0x01000193);
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}

const changed = [];
for (let i = 0; i < results.length; i++) {
  const row = rows[i] ? rows[i].json : {};
  const r = results[i].json;
  if (r.error) continue; // fetch failed — skip, do not overwrite the stored hash

  const markdown = r.result?.data?.content || r.result?.markdown || r.result?.content || (typeof r.result === 'string' ? r.result : JSON.stringify(r.result || ''));
  if (!markdown) continue;

  const newHash = contentHash(markdown);
  const oldHash = String(row.LastHash || '').trim();

  if (newHash !== oldHash) {
    changed.push({
      json: {
        URL: row.URL,
        Label: row.Label || row.URL,
        LastHash: newHash,
        firstRun: oldHash === ''
      }
    });
  }
}

return changed;

